func (m *UploadMock) MinimockWriteChunkDone() bool {
	if m.WriteChunkMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.WriteChunkMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.WriteChunkMock.invocationsDone()
}

// MinimockWriteChunkInspect logs each unmet expectation
func (m *UploadMock) MinimockWriteChunkInspect() {
	for _, e := range m.WriteChunkMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to UploadMock.WriteChunk at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterWriteChunkCounter := mm_atomic.LoadUint64(&m.afterWriteChunkCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.WriteChunkMock.defaultExpectation != nil && afterWriteChunkCounter < 1 {
		if m.WriteChunkMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to UploadMock.WriteChunk at\n%s", m.WriteChunkMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to UploadMock.WriteChunk at\n%s with params: %#v", m.WriteChunkMock.defaultExpectation.expectationOrigins.origin, *m.WriteChunkMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcWriteChunk != nil && afterWriteChunkCounter < 1 {
		m.t.Errorf("Expected call to UploadMock.WriteChunk at\n%s", m.funcWriteChunkOrigin)
	}

	if !m.WriteChunkMock.invocationsDone() && afterWriteChunkCounter > 0 {
		m.t.Errorf("Expected %d calls to UploadMock.WriteChunk at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.WriteChunkMock.expectedInvocations), m.WriteChunkMock.expectedInvocationsOrigin, afterWriteChunkCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *UploadMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockAbortInspect()

			m.MinimockFinalizeInspect()

			m.MinimockGetStatusInspect()

			m.MinimockInitiateInspect()

			m.MinimockWriteChunkInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *UploadMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *UploadMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockAbortDone() &&
		m.MinimockFinalizeDone() &&
		m.MinimockGetStatusDone() &&
		m.MinimockInitiateDone() &&
		m.MinimockWriteChunkDone()
}
